class SteamTradeInjector{constructor(){this.isInitialized=!1,this.pendingOrders=[],this.init()}init(){"loading"===document.readyState?document.addEventListener("DOMContentLoaded",()=>this.setup()):this.setup()}setup(){this.isSteamSite()&&(chrome.runtime.onMessage.addListener((message,sender,sendResponse)=>{this.handleMessage(message,sender,sendResponse)}),this.extractSteamSession(),this.isInitialized=!0)}isSteamSite(){return"steamcommunity.com"===window.location.hostname}handleMessage(message,sender,sendResponse){const handlers={CREATE_TRADE_OFFER:async()=>{try{const result=await this.createTradeOffer(message.order);sendResponse(result)}catch(error){sendResponse({success:!1,error:error.message})}},GET_STEAM_SESSION:()=>{sendResponse({success:!0,sessionData:this.getSteamSessionData()})}},handler=handlers[message.type];if(handler)return handler(),!0;sendResponse({success:!1,error:"Unknown message type"})}async createTradeOffer(order){try{const sessionData=this.getSteamSessionData();if(!sessionData.sessionId)throw new Error("Не удалось получить Steam session");const tradeData=this.prepareTradeData(order,sessionData),tradeOfferId=await this.sendTradeOffer(tradeData);return this.notifyTradeResult("TRADE_OFFER_CREATED",order.id,{tradeOfferId:tradeOfferId}),{success:!0,tradeOfferId:tradeOfferId,message:`Трейд-оффер #${tradeOfferId} отправлен покупателю`}}catch(error){throw this.notifyTradeResult("TRADE_OFFER_ERROR",order.id,{error:error.message}),error}}notifyTradeResult(type,orderId,data){chrome.runtime.sendMessage({type:type,orderId:orderId,...data})}getSteamSessionData(){return{sessionId:this.extractSessionId(),steamId:this.extractSteamId(),csrfToken:this.extractCSRFToken()}}extractSessionId(){if(window.g_sessionID)return window.g_sessionID;const sessionCookie=document.cookie.split(";").find(cookie=>cookie.trim().startsWith("sessionid="));return sessionCookie?sessionCookie.split("=")[1]:null}extractSteamId(){if(window.g_steamID)return window.g_steamID;const profileMatch=window.location.href.match(/steamcommunity\.com\/(profiles|id)\/([^\/]+)/);return profileMatch?profileMatch[2]:null}extractCSRFToken(){const metaToken=document.querySelector('meta[name="csrf-token"]');if(metaToken)return metaToken.getAttribute("content");const scripts=Array.from(document.querySelectorAll("script"));for(const script of scripts){const tokenMatch=script.textContent&&script.textContent.match(/sessionid['"]\s*:\s*['"]([^'"]+)['"]/);if(tokenMatch)return tokenMatch[1]}return null}prepareTradeData(order,sessionData){const tradeData={sessionid:sessionData.sessionId,partner:this.steamIdToAccountId(order.buyer.steam_id),tradeoffermessage:`Заказ #${order.id} с CS-SKINS.pro. Спасибо за покупку!`,json_tradeoffer:JSON.stringify({newversion:!0,version:2,me:{assets:order.items.map(item=>({appid:730,contextid:"2",amount:item.quantity,assetid:item.steam_asset_id})),currency:[],ready:!1},them:{assets:[],currency:[],ready:!1}}),captcha:"",trade_offer_create_params:JSON.stringify({trade_offer_access_token:this.extractTradeToken(order.buyer.trade_url)})};return tradeData}steamIdToAccountId(steamId64){return(BigInt(steamId64)-BigInt("76561197960265728")).toString()}extractTradeToken(tradeUrl){const tokenMatch=tradeUrl.match(/token=([a-zA-Z0-9_-]+)/);return tokenMatch?tokenMatch[1]:""}async sendTradeOffer(tradeData){try{const response=await fetch("https://steamcommunity.com/tradeoffer/new/send",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded; charset=UTF-8","X-Requested-With":"XMLHttpRequest"},body:new URLSearchParams(tradeData),credentials:"include"});if(!response.ok)throw new Error(`HTTP ${response.status}: ${response.statusText}`);const result=await response.json();if(result.strError)throw new Error(result.strError);if(!result.tradeofferid)throw new Error("Не получен ID трейд-оффера");return result.tradeofferid}catch(error){throw error}}extractSteamSession(){const sessionData=this.getSteamSessionData();sessionData.sessionId&&chrome.runtime.sendMessage({type:"STEAM_SESSION_EXTRACTED",sessionData:sessionData})}}const steamInjector=new SteamTradeInjector;window.steamInjector=steamInjector;